import asyncio
import websockets
import json
import uuid
from typing import Dict, Set, Optional
from dataclasses import dataclass, field, asdict
from datetime import datetime
import hashlib
import secrets

@dataclass
class Item:
    item_id: str
    name: str
    description: str
    value: int
    owner_id: Optional[str] = None
    
    def to_dict(self):
        return asdict(self)

@dataclass
class Player:
    player_id: str
    username: str
    inventory: Dict[str, Item] = field(default_factory=dict)
    gold: int = 1000
    
    def to_dict(self):
        return {
            'player_id': self.player_id,
            'username': self.username,
            'inventory': {k: v.to_dict() for k, v in self.inventory.items()},
            'gold': self.gold
        }

class TradeSession:
    def __init__(self, player1_id: str, player2_id: str):
        self.session_id = str(uuid.uuid4())
        self.player1_id = player1_id
        self.player2_id = player2_id
        self.player1_items: Set[str] = set()
        self.player2_items: Set[str] = set()
        self.player1_gold: int = 0
        self.player2_gold: int = 0
        self.player1_ready: bool = False
        self.player2_ready: bool = False
        self.lock = asyncio.Lock()
        self.active = True
        self.nonce = secrets.token_hex(16)
        
    def get_player_items(self, player_id: str) -> Set[str]:
        if player_id == self.player1_id:
            return self.player1_items
        return self.player2_items
    
    def get_player_gold(self, player_id: str) -> int:
        if player_id == self.player1_id:
            return self.player1_gold
        return self.player2_gold
    
    def set_player_items(self, player_id: str, items: Set[str]):
        if player_id == self.player1_id:
            self.player1_items = items
            self.player1_ready = False
        else:
            self.player2_items = items
            self.player2_ready = False
    
    def set_player_gold(self, player_id: str, gold: int):
        if player_id == self.player1_id:
            self.player1_gold = gold
            self.player1_ready = False
        else:
            self.player2_gold = gold
            self.player2_ready = False
    
    def set_ready(self, player_id: str, ready: bool):
        if player_id == self.player1_id:
            self.player1_ready = ready
        else:
            self.player2_ready = ready
    
    def is_ready(self, player_id: str) -> bool:
        if player_id == self.player1_id:
            return self.player1_ready
        return self.player2_ready
    
    def both_ready(self) -> bool:
        return self.player1_ready and self.player2_ready
    
    def get_other_player(self, player_id: str) -> str:
        return self.player2_id if player_id == self.player1_id else self.player1_id

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.trade_sessions: Dict[str, TradeSession] = {}
        self.player_trades: Dict[str, str] = {}
        self.global_lock = asyncio.Lock()
        self.item_locks: Dict[str, asyncio.Lock] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.transaction_log = []
        
        # Initialize some items
        self.item_templates = {
            'sword': {'name': 'Iron Sword', 'description': 'A sturdy iron sword', 'value': 100},
            'shield': {'name': 'Wooden Shield', 'description': 'A basic wooden shield', 'value': 50},
            'potion': {'name': 'Health Potion', 'description': 'Restores health', 'value': 25},
            'armor': {'name': 'Leather Armor', 'description': 'Light leather armor', 'value': 150},
        }
    
    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self.player_locks:
            self.player_locks[player_id] = asyncio.Lock()
        return self.player_locks[player_id]
    
    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        if item_id not in self.item_locks:
            self.item_locks[item_id] = asyncio.Lock()
        return self.item_locks[item_id]
    
    def _log_transaction(self, transaction_type: str, details: dict):
        log_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'type': transaction_type,
            'details': details,
            'hash': self._compute_hash(details)
        }
        self.transaction_log.append(log_entry)
    
    def _compute_hash(self, data: dict) -> str:
        data_str = json.dumps(data, sort_keys=True)
        return hashlib.sha256(data_str.encode()).hexdigest()
    
    async def register_player(self, websocket, username: str) -> str:
        player_id = str(uuid.uuid4())
        player = Player(player_id=player_id, username=username)
        
        # Give starting items
        for i, (template_key, template) in enumerate(self.item_templates.items()):
            if i < 2:  # Give first 2 items
                item_id = str(uuid.uuid4())
                item = Item(
                    item_id=item_id,
                    name=template['name'],
                    description=template['description'],
                    value=template['value'],
                    owner_id=player_id
                )
                player.inventory[item_id] = item
        
        async with self.global_lock:
            self.players[player_id] = player
            self.connections[player_id] = websocket
        
        self._log_transaction('player_register', {
            'player_id': player_id,
            'username': username,
            'initial_inventory': list(player.inventory.keys())
        })
        
        return player_id
    
    async def unregister_player(self, player_id: str):
        async with self.global_lock:
            if player_id in self.player_trades:
                trade_id = self.player_trades[player_id]
                await self.cancel_trade(player_id, trade_id)
            
            if player_id in self.connections:
                del self.connections[player_id]
    
    async def send_message(self, player_id: str, message: dict):
        if player_id in self.connections:
            try:
                await self.connections[player_id].send(json.dumps(message))
            except:
                pass
    
    async def broadcast_to_trade(self, trade_id: str, message: dict):
        if trade_id in self.trade_sessions:
            trade = self.trade_sessions[trade_id]
            await self.send_message(trade.player1_id, message)
            await self.send_message(trade.player2_id, message)
    
    async def initiate_trade(self, initiator_id: str, target_id: str) -> Optional[str]:
        if initiator_id not in self.players or target_id not in self.players:
            return None
        
        if initiator_id in self.player_trades or target_id in self.player_trades:
            return None
        
        trade = TradeSession(initiator_id, target_id)
        
        async with self.global_lock:
            self.trade_sessions[trade.session_id] = trade
            self.player_trades[initiator_id] = trade.session_id
            self.player_trades[target_id] = trade.session_id
        
        await self.send_message(target_id, {
            'type': 'trade_request',
            'trade_id': trade.session_id,
            'from_player': self.players[initiator_id].username,
            'from_player_id': initiator_id
        })
        
        self._log_transaction('trade_initiated', {
            'trade_id': trade.session_id,
            'initiator_id': initiator_id,
            'target_id': target_id
        })
        
        return trade.session_id
    
    async def add_items_to_trade(self, player_id: str, trade_id: str, item_ids: list):
        if trade_id not in self.trade_sessions:
            return {'success': False, 'error': 'Trade not found'}
        
        trade = self.trade_sessions[trade_id]
        
        if player_id not in [trade.player1_id, trade.player2_id]:
            return {'success': False, 'error': 'Not part of this trade'}
        
        async with trade.lock:
            if not trade.active:
                return {'success': False, 'error': 'Trade is not active'}
            
            player = self.players[player_id]
            
            # Verify all items belong to player
            for item_id in item_ids:
                if item_id not in player.inventory:
                    return {'success': False, 'error': f'Item {item_id} not in inventory'}
                if player.inventory[item_id].owner_id != player_id:
                    return {'success': False, 'error': f'Item {item_id} not owned by player'}
            
            trade.set_player_items(player_id, set(item_ids))
            
            await self.broadcast_to_trade(trade_id, {
                'type': 'trade_updated',
                'trade_id': trade_id,
                'player_id': player_id,
                'items': item_ids,
                'gold': trade.get_player_gold(player_id)
            })
            
            return {'success': True}
    
    async def add_gold_to_trade(self, player_id: str, trade_id: str, gold: int):
        if trade_id not in self.trade_sessions:
            return {'success': False, 'error': 'Trade not found'}
        
        trade = self.trade_sessions[trade_id]
        
        if player_id not in [trade.player1_id, trade.player2_id]:
            return {'success': False, 'error': 'Not part of this trade'}
        
        async with trade.lock:
            if not trade.active:
                return {'success': False, 'error': 'Trade is not active'}
            
            player = self.players[player_id]
            
            if gold < 0 or gold > player.gold:
                return {'success': False, 'error': 'Invalid gold amount'}
            
            trade.set_player_gold(player_id, gold)
            
            await self.broadcast_to_trade(trade_id, {
                'type': 'trade_updated',
                'trade_id': trade_id,
                'player_id': player_id,
                'items': list(trade.get_player_items(player_id)),
                'gold': gold
            })
            
            return {'success': True}
    
    async def set_trade_ready(self, player_id: str, trade_id: str, ready: bool):
        if trade_id not in self.trade_sessions:
            return {'success': False, 'error': 'Trade not found'}
        
        trade = self.trade_sessions[trade_id]
        
        if player_id not in [trade.player1_id, trade.player2_id]:
            return {'success': False, 'error': 'Not part of this trade'}
        
        async with trade.lock:
            if not trade.active:
                return {'success': False, 'error': 'Trade is not active'}
            
            trade.set_ready(player_id, ready)
            
            await self.broadcast_to_trade(trade_id, {
                'type': 'trade_ready_status',
                'trade_id': trade_id,
                'player_id': player_id,
                'ready': ready
            })
            
            if trade.both_ready():
                result = await self.execute_trade(trade_id)
                return result
            
            return {'success': True, 'ready': ready}
    
    async def execute_trade(self, trade_id: str):
        if trade_id not in self.trade_sessions:
            return {'success': False, 'error': 'Trade not found'}
        
        trade = self.trade_sessions[trade_id]
        
        async with trade.lock:
            if not trade.active:
                return {'success': False, 'error': 'Trade already executed or cancelled'}
            
            if not trade.both_ready():
                return {'success': False, 'error': 'Both players must be ready'}
            
            player1 = self.players[trade.player1_id]
            player2 = self.players[trade.player2_id]
            
            # Acquire locks in consistent order to prevent deadlock
            lock_order = sorted([trade.player1_id, trade.player2_id])
            lock1 = self._get_player_lock(lock_order[0])
            lock2 = self._get_player_lock(lock_order[1])
            
            async with lock1:
                async with lock2:
                    # Verify gold amounts
                    if player1.gold < trade.player1_gold:
                        trade.active = False
                        await self.broadcast_to_trade(trade_id, {
                            'type': 'trade_failed',
                            'trade_id': trade_id,
                            'reason': 'Insufficient gold'
                        })
                        return {'success': False, 'error': 'Insufficient gold'}
                    
                    if player2.gold < trade.player2_gold:
                        trade.active = False
                        await self.broadcast_to_trade(trade_id, {
                            'type': 'trade_failed',
                            'trade_id': trade_id,
                            'reason': 'Insufficient gold'
                        })
                        return {'success': False, 'error': 'Insufficient gold'}
                    
                    # Verify all items still exist and belong to correct players
                    for item_id in trade.player1_items:
                        if item_id not in player1.inventory:
                            trade.active = False
                            await self.broadcast_to_trade(trade_id, {
                                'type': 'trade_failed',
                                'trade_id': trade_id,
                                'reason': 'Item no longer available'
                            })
                            return {'success': False, 'error': 'Item no longer available'}
                        if player1.inventory[item_id].owner_id != trade.player1_id:
                            trade.active = False
                            await self.broadcast_to_trade(trade_id, {
                                'type': 'trade_failed',
                                'trade_id': trade_id,
                                'reason': 'Item ownership mismatch'
                            })
                            return {'success': False, 'error': 'Item ownership mismatch'}
                    
                    for item_id in trade.player2_items:
                        if item_id not in player2.inventory:
                            trade.active = False
                            await self.broadcast_to_trade(trade_id, {
                                'type': 'trade_failed',
                                'trade_id': trade_id,
                                'reason': 'Item no longer available'
                            })
                            return {'success': False, 'error': 'Item no longer available'}
                        if player2.inventory[item_id].owner_id != trade.player2_id:
                            trade.active = False
                            await self.broadcast_to_trade(trade_id, {
                                'type': 'trade_failed',
                                'trade_id': trade_id,
                                'reason': 'Item ownership mismatch'
                            })
                            return {'success': False, 'error': 'Item ownership mismatch'}
                    
                    # Execute the trade atomically
                    # Transfer items from player1 to player2
                    items_to_p2 = []
                    for item_id in trade.player1_items:
                        item = player1.inventory.pop(item_id)
                        item.owner_id = trade.player2_id
                        player2.inventory[item_id] = item
                        items_to_p2.append(item_id)
                    
                    # Transfer items from player2 to player1
                    items_to_p1 = []
                    for item_id in trade.player2_items:
                        item = player2.inventory.pop(item_id)
                        item.owner_id = trade.player1_id
                        player1.inventory[item_id] = item
                        items_to_p1.append(item_id)
                    
                    # Transfer gold
                    player1.gold -= trade.player1_gold
                    player1.gold += trade.player2_gold
                    player2.gold -= trade.player2_gold
                    player2.gold += trade.player1_gold
                    
                    trade.active = False
                    
                    self._log_transaction('trade_executed', {
                        'trade_id': trade_id,
                        'player1_id': trade.player1_id,
                        'player2_id': trade.player2_id,
                        'player1_items': items_to_p2,
                        'player2_items': items_to_p1,
                        'player1_gold': trade.player1_gold,
                        'player2_gold': trade.player2_gold,
                        'nonce': trade.nonce
                    })
            
            # Notify both players
            await self.send_message(trade.player1_id, {
                'type': 'trade_completed',
                'trade_id': trade_id,
                'received_items': items_to_p1,
                'sent_items': items_to_p2,
                'gold_change': trade.player2_gold - trade.player1_gold,
                'new_inventory': player1.to_dict()['inventory'],
                'new_gold': player1.gold
            })
            
            await self.send_message(trade.player2_id, {
                'type': 'trade_completed',
                'trade_id': trade_id,
                'received_items': items_to_p2,
                'sent_items': items_to_p1,
                'gold_change': trade.player1_gold - trade.player2_gold,
                'new_inventory': player2.to_dict()['inventory'],
                'new_gold': player2.gold
            })
            
            # Clean up
            async with self.global_lock:
                del self.player_trades[trade.player1_id]
                del self.player_trades[trade.player2_id]
                del self.trade_sessions[trade_id]
            
            return {'success': True}
    
    async def cancel_trade(self, player_id: str, trade_id: str):
        if trade_id not in self.trade_sessions:
            return {'success': False, 'error': 'Trade not found'}
        
        trade = self.trade_sessions[trade_id]
        
        async with trade.lock:
            trade.active = False
            
            await self.broadcast_to_trade(trade_id, {
                'type': 'trade_cancelled',
                'trade_id': trade_id,
                'cancelled_by': player_id
            })
            
            self._log_transaction('trade_cancelled', {
                'trade_id': trade_id,
                'cancelled_by': player_id
            })
        
        async with self.global_lock:
            if trade.player1_id in self.player_trades:
                del self.player_trades[trade.player1_id]
            if trade.player2_id in self.player_trades:
                del self.player_trades[trade.player2_id]
            if trade_id in self.trade_sessions:
                del self.trade_sessions[trade_id]
        
        return {'success': True}
    
    async def handle_client(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                data = json.loads(message)
                action = data.get('action')
                
                if action == 'register':
                    username = data.get('username', 'Player')
                    player_id = await self.register_player(websocket, username)
                    await websocket.send(json.dumps({
                        'type': 'registered',
                        'player_id': player_id,
                        'player_data': self.players[player_id].to_dict()
                    }))
                
                elif action == 'get_inventory':
                    if player_id and player_id in self.players:
                        await websocket.send(json.dumps({
                            'type': 'inventory',
                            'inventory': self.players[player_id].to_dict()['inventory'],
                            'gold': self.players[player_id].gold
                        }))
                
                elif action == 'initiate_trade':
                    target_id = data.get('target_player_id')
                    if player_id:
                        trade_id = await self.initiate_trade(player_id, target_id)
                        if trade_id:
                            await websocket.send(json.dumps({
                                'type': 'trade_initiated',
                                'trade_id': trade_id
                            }))
                        else:
                            await websocket.send(json.dumps({
                                'type': 'error',
                                'message': 'Could not initiate trade'
                            }))
                
                elif action == 'add_items_to_trade':
                    trade_id = data.get('trade_id')
                    item_ids = data.get('item_ids', [])
                    if player_id:
                        result = await self.add_items_to_trade(player_id, trade_id, item_ids)
                        await websocket.send(json.dumps(result))
                
                elif action == 'add_gold_to_trade':
                    trade_id = data.get('trade_id')
                    gold = data.get('gold', 0)
                    if player_id:
                        result = await self.add_gold_to_trade(player_id, trade_id, gold)
                        await websocket.send(json.dumps(result))
                
                elif action == 'set_ready':
                    trade_id = data.get('trade_id')
                    ready = data.get('ready', False)
                    if player_id:
                        result = await self.set_trade_ready(player_id, trade_id, ready)
                        await websocket.send(json.dumps(result))
                
                elif action == 'cancel_trade':
                    trade_id = data.get('trade_id')
                    if player_id:
                        result = await self.cancel_trade(player_id, trade_id)
                        await websocket.send(json.dumps(result))
        
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            if player_id:
                await self.unregister_player(player_id)

async def main():
    server = GameServer()
    async with websockets.serve(server.handle_client, "localhost", 8765):
        print("Game server started on ws://localhost:8765")
        await asyncio.Future()

if __name__ == "__main__":
    asyncio.run(main())